return [
  { "area": "Legal & Compliance",   "canvas_id": "F0B3HRZ1CLD" },
  { "area": "Trading Desk",         "canvas_id": "F0B3QS12ASY" },
  { "area": "Operations",           "canvas_id": "F0B3M7YP4CS" },
  { "area": "Finance & Accounting", "canvas_id": "F0B3QS32XRS" },
  { "area": "Sales & Partnerships", "canvas_id": "F0B3P3AKCHX" },
  { "area": "Management",           "canvas_id": "F0B3QS4UTFE" }
].map(a => ({ json: a }));

const getSlackUrl = (desc) => {
  if (!desc?.content) return null;
  const walk = (nodes) => {
    for (const node of (nodes || [])) {
      for (const mark of (node.marks || []))
        if (mark.type === 'link' && (mark.attrs?.href || '').includes('slack.com')) return mark.attrs.href;
      const found = walk(node.content);
      if (found) return found;
    }
    return null;
  };
  return walk(desc.content);
};

const getBlockedReason = (f) => {
  if (!f) return '';
  if (typeof f === 'string') return f.trim();
  if (Array.isArray(f)) return f.map(x => x.value || x.name || String(x)).join(', ');
  if (typeof f === 'object') {
    if (f.content) {
      const texts = [];
      const walk = (nodes) => { for (const n of (nodes || [])) { if (n.type === 'text') texts.push(n.text); walk(n.content); } };
      walk(f.content);
      return texts.join(' ').trim();
    }
    return f.value || f.name || f.text || f.displayName || '';
  }
  return String(f);
};

const getStatusEnteredAt = (issue) => {
  const histories = (issue.changelog?.histories || []).slice().sort((a, b) => new Date(b.created) - new Date(a.created));
  for (const h of histories) {
    if ((h.items || []).some(item => item.field === 'status')) return h.created;
  }
  return issue.fields?.created || null;
};

const daysSince = (dateStr) => {
  if (!dateStr) return null;
  return Math.floor((Date.now() - new Date(dateStr).getTime()) / (1000 * 60 * 60 * 24));
};

const getAmKey = (issue) => {
  const links = issue.fields?.issuelinks || [];
  const amLink = links.find(l => l.outwardIssue?.key?.startsWith('AM-') && l.type?.outward === 'causes');
  return amLink?.outwardIssue?.key || null;
};

const TECH_STATUSES = ['sent to dev', 'ready for dev', 'in development'];

const cleanIssues = (raw) => (raw || []).map(i => ({
  key:           i.key || '',
  summary:       i.fields?.summary || '',
  statusName:    i.fields?.status?.name || '',
  slackUrl:      getSlackUrl(i.fields?.description) || '',
  blockedReason: getBlockedReason(i.fields?.customfield_10239),
  createdAt:     i.fields?.created || null,
  amKey:         getAmKey(i),
  daysInStatus:  (() => {
    const s = (i.fields?.status?.name || '').toLowerCase();
    if (TECH_STATUSES.includes(s)) return null;
    if (s === 'blocked') return daysSince(getStatusEnteredAt(i));
    return daysSince(i.fields?.created);
  })()
}));

const isCalledByWorkflow = (() => {
  try { return !!$('When Called by Another Workflow').first()?.json?.area; } catch(e) { return false; }
})();

if (isCalledByWorkflow) {
  const caller = $('When Called by Another Workflow').first().json;
  return [{ json: { area: caller.area || '', canvas_id: caller.canvas_id || '', issues: cleanIssues($input.first().json.issues) } }];
}

const fetchAll = $input.all();
const areasAll = $('All Areas').all();
return fetchAll.map((fetchItem, i) => {
  const areaData = areasAll[i]?.json || {};
  return { json: { area: areaData.area || '', canvas_id: areaData.canvas_id || '', issues: cleanIssues(fetchItem.json.issues) } };
});

const items = $input.all();
const amKeys = [...new Set(items.flatMap(item => item.json.issues || []).map(iss => iss.amKey).filter(Boolean))];
return [{ json: { areas: items.map(i => i.json), amKeys } }];

