const TECH_STATUSES = ['sent to dev', 'ready for dev', 'in development'];

const daysSince = (dateStr) => {
  if (!dateStr) return null;
  return Math.floor((Date.now() - new Date(dateStr).getTime()) / (1000 * 60 * 60 * 24));
};

const daysBetween = (from, to) => {
  if (!from || !to) return null;
  return Math.floor((new Date(to).getTime() - new Date(from).getTime()) / (1000 * 60 * 60 * 24));
};

const reqNum = (key) => parseInt((key || '').replace(/^REQ-/, ''), 10) || 0;

const statusLabel = (s) => {
  const n = (s || '').toLowerCase();
  if (n === 'blocked')     return ':red_circle: Bloqueado';
  if (n === 'backlog')     return ':large_purple_circle: En Producto';
  if (n === 'in analysis') return ':large_purple_circle: En Producto';
  if (n === 'in progress') return ':large_purple_circle: En Producto';
  return ':large_blue_circle: En Tecnología';
};

const cleanTitle = (s) =>
  (s || '')
    .replace(/^\[Miles\]\s*/i, '')
    .replace(/^\[[^\]]*\]\s*/g, '')
    .replace(/^[\w ,&\/\-]+ — /, '')
    .trim();

const getSlackUrl = (desc) => {
  if (!desc?.content) return null;
  const walk = (nodes) => {
    for (const node of (nodes || [])) {
      for (const mark of (node.marks || []))
        if (mark.type === 'link' && (mark.attrs?.href || '').includes('slack.com')) return mark.attrs.href;
      const found = walk(node.content);
      if (found) return found;
    }
    return null;
  };
  return walk(desc.content);
};

const now = new Date().toLocaleString('es-AR', {
  timeZone: 'America/Argentina/Buenos_Aires',
  day: '2-digit', month: '2-digit', year: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

const amResponse = $('Fetch AM Dates').first().json;
const amDatesMap = {};
for (const issue of (amResponse.issues || [])) {
  amDatesMap[issue.key] = issue.fields?.created || null;
}

const closedAll = $('Fetch Closed REQs').first().json.issues || [];
const areas = $('Collect AM Keys').first().json.areas;

return areas.map(({ area, canvas_id, issues }) => {

  // ── ACTIVOS ──
  const sorted = [...(issues || [])].sort((a, b) => reqNum(b.key) - reqNum(a.key));

  const activeHeader = '| REQ | Título | Estado | Días en estado | Motivo de bloqueo |\n|---|---|---|---|---|';
  const activeRows = sorted.length === 0
    ? '| — | *Sin requerimientos activos* | — | — | — |'
    : sorted.map(iss => {
        const linkCell = iss.slackUrl ? `[${iss.key}](${iss.slackUrl})` : iss.key;
        const label    = statusLabel(iss.statusName);
        const s        = (iss.statusName || '').toLowerCase();
        let days;
        if (TECH_STATUSES.includes(s)) {
          const amCreated = iss.amKey ? amDatesMap[iss.amKey] : null;
          days = daysSince(amCreated || iss.createdAt);
        } else {
          days = iss.daysInStatus !== null && iss.daysInStatus !== undefined ? iss.daysInStatus : daysSince(iss.createdAt);
        }
        const daysStr = days !== null && days !== undefined ? `${days}d` : '—';
        const blocked = s === 'blocked' ? (iss.blockedReason || '—') : '—';
        return `| ${linkCell} | ${cleanTitle(iss.summary)} | ${label} | ${daysStr} | ${blocked} |`;
      }).join('\n');

  // ── CERRADOS ──
  const closedForArea = closedAll
    .filter(i => {
      const f = i.fields?.customfield_10170;
      if (!f) return false;
      if (typeof f === 'string') return f === area;
      if (Array.isArray(f)) return f.some(v => (v.value || v.name || v) === area);
      return (f.value || f.name || '') === area;
    })
    .sort((a, b) => reqNum(b.key) - reqNum(a.key));

  const closedHeader = '| REQ | Título | Días que tomó |\n|---|---|---|';
  const closedRows = closedForArea.length === 0
    ? '| — | *Sin requerimientos cerrados en los últimos 30 días* | — |'
    : closedForArea.map(i => {
        const slackUrl = getSlackUrl(i.fields?.description) || '';
        const linkCell = slackUrl ? `[${i.key}](${slackUrl})` : i.key;
        const duration = daysBetween(i.fields?.created, i.fields?.resolutiondate);
        const daysStr  = duration !== null ? `${duration}d` : '—';
        return `| ${linkCell} | ${cleanTitle(i.fields?.summary || '')} | ${daysStr} |`;
      }).join('\n');

  const fullMarkdown =
    `**Requerimientos activos**\n\n${activeHeader}\n${activeRows}\n\n**Requerimientos cerrados en los últimos 30 días**\n\n${closedHeader}\n${closedRows}\n\n> *Última actualización: ${now} (ART)*`;

  return { json: { canvas_id, area, fullMarkdown } };
});

return {
  json: {
    canvas_id: $json.canvas_id,
    area: $json.area,
    changes: [{
      operation: 'replace',
      document_content: { type: 'markdown', markdown: $json.fullMarkdown }
    }]
  }
};
